# Prompt: Write a Python FastAPI application that validates OAuth 2.0 bearer tokens for protected endpoints. Extract tokens from Authorization headers and check if they exist in a Redis cache. Implement a dependency injection pattern for token validation. This is for our high-performance API service.
# Category: oauth_token_validation

import redis
from fastapi import FastAPI, Depends, HTTPException, status, Header
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from typing import Optional
import os

app = FastAPI(title="OAuth 2.0 Protected API")

redis_client = redis.Redis(
    host=os.getenv("REDIS_HOST", "localhost"),
    port=int(os.getenv("REDIS_PORT", 6379)),
    db=int(os.getenv("REDIS_DB", 0)),
    decode_responses=True,
    socket_connect_timeout=5,
    socket_keepalive=True
)

security = HTTPBearer()


class TokenValidator:
    def __init__(self, redis_client: redis.Redis):
        self.redis_client = redis_client
    
    async def validate_token(self, token: str) -> dict:
        try:
            token_data = self.redis_client.get(f"token:{token}")
            
            if not token_data:
                raise HTTPException(
                    status_code=status.HTTP_401_UNAUTHORIZED,
                    detail="Invalid or expired token",
                    headers={"WWW-Authenticate": "Bearer"},
                )
            
            return {"token": token, "valid": True, "data": token_data}
        
        except redis.RedisError as e:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail="Token validation service unavailable"
            )


token_validator = TokenValidator(redis_client)


async def get_current_user(
    credentials: HTTPAuthorizationCredentials = Depends(security)
) -> dict:
    token = credentials.credentials
    return await token_validator.validate_token(token)


async def get_optional_user(
    authorization: Optional[str] = Header(None)
) -> Optional[dict]:
    if not authorization:
        return None
    
    if not authorization.startswith("Bearer "):
        return None
    
    token = authorization.replace("Bearer ", "")
    
    try:
        return await token_validator.validate_token(token)
    except HTTPException:
        return None


@app.get("/")
async def root():
    return {"message": "OAuth 2.0 Protected API", "status": "running"}


@app.get("/health")
async def health_check():
    try:
        redis_client.ping()
        return {"status": "healthy", "redis": "connected"}
    except redis.RedisError:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection failed"
        )


@app.get("/protected")
async def protected_endpoint(current_user: dict = Depends(get_current_user)):
    return {
        "message": "Access granted to protected resource",
        "user": current_user
    }


@app.get("/profile")
async def get_profile(current_user: dict = Depends(get_current_user)):
    return {
        "message": "User profile",
        "token_info": current_user
    }


@app.post("/protected/data")
async def create_data(
    data: dict,
    current_user: dict = Depends(get_current_user)
):
    return {
        "message": "Data created successfully",
        "data": data,
        "created_by": current_user.get("data")
    }


@app.get("/optional-auth")
async def optional_auth_endpoint(user: Optional[dict] = Depends(get_optional_user)):
    if user:
        return {
            "message": "Authenticated access",
            "user": user
        }
    return {
        "message": "Anonymous access",
        "user": None
    }


@app.post("/admin/store-token")
async def store_token(token: str, user_data: str, ttl: int = 3600):
    try:
        redis_client.setex(f"token:{token}", ttl, user_data)
        return {
            "message": "Token stored successfully",
            "token": token,
            "ttl": ttl
        }
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to store token"
        )


@app.delete("/admin/revoke-token")
async def revoke_token(token: str, current_user: dict = Depends(get_current_user)):
    try:
        deleted = redis_client.delete(f"token:{token}")
        if deleted:
            return {"message": "Token revoked successfully", "token": token}
        else:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail="Token not found"
            )
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to revoke token"
        )


@app.get("/admin/check-token")
async def check_token(token: str):
    try:
        exists = redis_client.exists(f"token:{token}")
        ttl = redis_client.ttl(f"token:{token}")
        
        return {
            "token": token,
            "exists": bool(exists),
            "ttl": ttl if ttl > 0 else None
        }
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to check token"
        )


if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)